import { Item, Customer } from './types.js';
import {
  getItemSpec,
  isComponentType,
  isKnownType,
  COMPONENT_BLOCK_PREMIUM,
  COMPONENT_BLOCK_SIZE,
} from './catalogue.js';

const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_YEARS = 2;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
const PROCESSING_FEE = 5;

function basePremiumForItem(item: Item): number {
  if (isComponentType(item.type)) {
    return getItemSpec(item.type).basePremium;
  }
  return getItemSpec(item.type).basePremium;
}

function componentsBasePremium(items: Item[]): number {
  const groups: Record<string, number> = {};
  for (const item of items) {
    if (isComponentType(item.type)) {
      groups[item.type] = (groups[item.type] || 0) + 1;
    }
  }
  let total = 0;
  for (const type of Object.keys(groups)) {
    const count = groups[type];
    const spec = getItemSpec(type);
    if (count === COMPONENT_BLOCK_SIZE) {
      total += COMPONENT_BLOCK_PREMIUM;
    } else {
      const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
      // Per spec: "block requires exactly 3" - 4 runes -> 100 G (no block).
      // But 3+3 = 120 G (two separate blocks). So blocks apply only when exact match.
      // Reading again: "3 runes → 60 G (block applies)"; "4 runes → 100 G (no block — block requires exactly 3)";
      // "3 runes + 3 moonstones → 120 G base premium (two separate blocks)".
      // So per-type: if count == 3 then block, else full price each. What about 6 runes? Unspecified.
      // Safest: only exactly 3 of one type triggers the block.
      void blocks;
      total += count * spec.basePremium;
    }
  }
  return total;
}

function mainItemsBasePremium(items: Item[]): number {
  let total = 0;
  for (const item of items) {
    if (!isComponentType(item.type)) {
      total += getItemSpec(item.type).basePremium;
    }
  }
  return total;
}

function itemBasePremiumWithItemModifiers(item: Item): number {
  const base = basePremiumForItem(item);
  let surcharge = 0;
  if (item.cursed) {
    surcharge += base * CURSE_SURCHARGE;
  }
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE;
  }
  return base + surcharge;
}

function policyBaseWithComponentBlocks(items: Item[]): number {
  return mainItemsBasePremium(items) + componentsBasePremium(items);
}

function itemSpecificSurcharges(items: Item[]): number {
  let total = 0;
  for (const item of items) {
    const base = basePremiumForItem(item);
    if (item.cursed) {
      total += base * CURSE_SURCHARGE;
    }
    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
      total += base * HIGH_ENCHANTMENT_SURCHARGE;
    }
  }
  return total;
}

function validateItems(items: Item[]): void {
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
}

export interface PremiumContext {
  customer: Customer;
  quoteIndex: number; // 0-based index among quotes in scenario
}

export function computePremium(items: Item[], ctx: PremiumContext): number {
  validateItems(items);

  const policyBase = policyBaseWithComponentBlocks(items);
  const itemSurcharges = itemSpecificSurcharges(items);

  let total = policyBase + itemSurcharges;

  // Policy-wide modifiers apply to the policy base premium (sum of item base premiums)
  if (ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS) {
    total -= policyBase * LOYALTY_DISCOUNT;
  }
  // First insurance: per spec, each item in a quote is a first insurance.
  // The integration example shows: 100 base + 50 curse + 30 high + 10 first
  // -20 loyalty - 15 followup = 155 + 5 fee = 160.
  // Loyalty -20 = 20% of 100 (policy base). First insurance +10 = 10% of 100.
  // Followup -15 = 15% of 100.
  // So all policy-wide modifiers apply to policyBase.
  total += policyBase * FIRST_INSURANCE_SURCHARGE;

  if (ctx.quoteIndex > 0) {
    total -= policyBase * FOLLOWUP_CONTRACT_DISCOUNT;
  }

  total += PROCESSING_FEE;

  // Round up in MHPCO's favor
  return Math.ceil(total);
}

