import { Policy, Incident, DamageEntry, Item, ClaimResult } from './types.js';
import { isKnownType } from './catalogue.js';

const DEDUCTIBLE = 100;
const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
const HIGH_ENCHANTMENT_PAYOUT_FACTOR = 0.5;
const DRAGON_MATERIAL = 'dragon';

function matchDamagesToItems(items: Item[], damages: DamageEntry[]): Item[] {
  // Allocate each damage to one item of the same type.
  // If there are more damages of a type than items, throw.
  const itemsByType: Record<string, Item[]> = {};
  for (const item of items) {
    if (!itemsByType[item.type]) itemsByType[item.type] = [];
    itemsByType[item.type].push(item);
  }
  // Track consumption per type
  const consumed: Record<string, number> = {};
  const matched: Item[] = [];
  for (const damage of damages) {
    if (!isKnownType(damage.itemType)) {
      throw new Error(`Unknown damaged item type: ${damage.itemType}`);
    }
    const available = itemsByType[damage.itemType];
    const used = consumed[damage.itemType] || 0;
    if (!available || used >= available.length) {
      throw new Error(
        `Damage references ${damage.itemType} not covered by the policy`
      );
    }
    matched.push(available[used]);
    consumed[damage.itemType] = used + 1;
  }
  return matched;
}

function payoutForDamage(item: Item, amount: number): number {
  if (amount < 0) {
    throw new Error(`Damage amount must be non-negative, got ${amount}`);
  }
  let reimbursable = amount;
  const isDragon = item.material === DRAGON_MATERIAL;
  const isHighEnchant =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;

  if (isHighEnchant && !isDragon) {
    reimbursable = amount * HIGH_ENCHANTMENT_PAYOUT_FACTOR;
  }
  // Dragon material: full reimbursement (overrides high enchantment per spec?)
  // Actually the spec says:
  //   dragon, ench 9, damage 1000 -> payout 400 (both clauses; 50% wins, then deductible)
  // So when BOTH apply, the 50% rule wins.
  // Re-check: "dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G
  //  (high-enchantment clause applies, then deductible)" → 500 - 100 = 400.
  // So 50% always wins over dragon when both apply.
  if (isHighEnchant) {
    reimbursable = amount * HIGH_ENCHANTMENT_PAYOUT_FACTOR;
  } else if (isDragon) {
    reimbursable = amount;
  }

  const afterDeductible = reimbursable - DEDUCTIBLE;
  return Math.max(0, afterDeductible);
}

export function processClaim(policy: Policy, incident: Incident): ClaimResult {
  const matchedItems = matchDamagesToItems(policy.items, incident.damages);

  // Validate amounts first (negative check)
  for (const damage of incident.damages) {
    if (damage.amount < 0) {
      throw new Error(`Damage amount must be non-negative, got ${damage.amount}`);
    }
  }

  let totalPayout = 0;
  for (let i = 0; i < incident.damages.length; i++) {
    totalPayout += payoutForDamage(matchedItems[i], incident.damages[i].amount);
  }

  // Round payouts down (in MHPCO's favor)
  let payout = Math.floor(totalPayout);

  // Apply remaining cap
  if (payout > policy.remainingCap) {
    payout = policy.remainingCap;
  }
  policy.remainingCap -= payout;

  return {
    payout,
    remainingCap: policy.remainingCap,
  };
}

