import { Scenario, ScenarioResult, StepResult, Policy } from './types.js';
import { computePremium } from './premium.js';
import { makePolicy } from './policy.js';
import { processClaim } from './claim.js';

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  const policies: Record<number, Policy> = {};
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === 'quote') {
      const premium = computePremium(step.items, {
        customer: scenario.customer,
        quoteIndex: quoteCount,
      });
      const policy = makePolicy(step.items);
      policies[i] = policy;
      quoteCount += 1;
      results.push({ premium });
    } else if (step.op === 'claim') {
      const policy = policies[step.policy];
      if (!policy) {
        throw new Error(
          `Claim step ${i} references non-existent policy ${step.policy}`
        );
      }
      const claimResult = processClaim(policy, step.incident);
      results.push(claimResult);
    } else {
      throw new Error(`Unknown step op: ${(step as { op: string }).op}`);
    }
  }

  return { results };
}

