  it('sword with exactly enchantment 5 → high-enchantment surcharge applies (130 G + 5 = 135)', () => {
    // 100 base + 30 high = 130, +10 first = 140, +5 fee = 145
    expect(
      premiumOf({
        customer: { yearsWithMHPCO: 0 },
        steps: [quote([{ type: 'sword', enchantment: 5 }])],
      })
    ).toBe(145);
