  it('sword with enchantment 5 and cursed → both surcharges apply', () => {
    // 100 base + 50 curse + 30 high = 180, +10 first = 190, +5 fee = 195
    expect(
      premiumOf({
        customer: { yearsWithMHPCO: 0 },
        steps: [quote([{ type: 'sword', enchantment: 5, cursed: true }])],
      })
