  it('sword with enchantment 4 → no high-enchantment surcharge', () => {
    // 100 base, +10 first, +5 fee = 115
    expect(
      premiumOf({
        customer: { yearsWithMHPCO: 0 },
        steps: [quote([{ type: 'sword', enchantment: 4 }])],
      })
    ).toBe(115);
