1	import { Policy, Incident, DamageEntry, Item, ClaimResult } from './types.js';
2	import { isKnownType } from './catalogue.js';
3	
4	const DEDUCTIBLE = 100;
5	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
6	const HIGH_ENCHANTMENT_PAYOUT_FACTOR = 0.5;
7	
8	function matchDamagesToItems(items: Item[], damages: DamageEntry[]): Item[] {
9	  const itemsByType: Record<string, Item[]> = {};
10	  for (const item of items) {
11	    if (!itemsByType[item.type]) itemsByType[item.type] = [];
12	    itemsByType[item.type].push(item);
13	  }
14	  const consumed: Record<string, number> = {};
15	  const matched: Item[] = [];
16	  for (const damage of damages) {
17	    if (!isKnownType(damage.itemType)) {
18	      throw new Error(`Unknown damaged item type: ${damage.itemType}`);
19	    }
20	    const available = itemsByType[damage.itemType];
21	    const used = consumed[damage.itemType] ?? 0;
22	    if (!available || used >= available.length) {
23	      throw new Error(
24	        `Damage references ${damage.itemType} not covered by the policy`
25	      );
26	    }
27	    matched.push(available[used]);
28	    consumed[damage.itemType] = used + 1;
29	  }
30	  return matched;
31	}
32	
33	// Reimbursement factor per the spec:
34	//   - high enchantment (>= 8): 50% (wins over dragon when both apply)
35	//   - dragon material: 100%
36	//   - otherwise: 100%
37	function reimbursementFactor(item: Item): number {
38	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
39	    return HIGH_ENCHANTMENT_PAYOUT_FACTOR;
40	  }
41	  return 1;
42	}
43	
44	function payoutForDamage(item: Item, amount: number): number {
45	  const reimbursable = amount * reimbursementFactor(item);
46	  return Math.max(0, reimbursable - DEDUCTIBLE);
47	}
48	
49	function validateDamageAmounts(damages: DamageEntry[]): void {
50	  for (const damage of damages) {
51	    if (damage.amount < 0) {
52	      throw new Error(`Damage amount must be non-negative, got ${damage.amount}`);
53	    }
54	  }
55	}
56	
57	export function processClaim(policy: Policy, incident: Incident): ClaimResult {
58	  validateDamageAmounts(incident.damages);
59	  const matchedItems = matchDamagesToItems(policy.items, incident.damages);
60	
61	  let totalPayout = 0;
62	  for (let i = 0; i < incident.damages.length; i++) {
63	    totalPayout += payoutForDamage(matchedItems[i], incident.damages[i].amount);
64	  }
65	
66	  // Round down in MHPCO's favor, then cap.
67	  const requested = Math.floor(totalPayout);
68	  const payout = Math.min(requested, policy.remainingCap);
69	  policy.remainingCap -= payout;
70	
71	  return { payout, remainingCap: policy.remainingCap };
72	}

1	import { Item, Customer } from './types.js';
2	import {
3	  getItemSpec,
4	  isComponentType,
5	  isKnownType,
6	  COMPONENT_BLOCK_PREMIUM,
7	  COMPONENT_BLOCK_SIZE,
8	} from './catalogue.js';
9	
10	const CURSE_SURCHARGE = 0.5;
11	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const LOYALTY_DISCOUNT = 0.2;
14	const LOYALTY_YEARS = 2;
15	const FIRST_INSURANCE_SURCHARGE = 0.1;
16	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
17	const PROCESSING_FEE = 5;
18	
19	function basePremiumFor(item: Item): number {
20	  return getItemSpec(item.type).basePremium;
21	}
22	
23	function countByType(items: Item[]): Record<string, number> {
24	  const counts: Record<string, number> = {};
25	  for (const item of items) {
26	    counts[item.type] = (counts[item.type] ?? 0) + 1;
27	  }
28	  return counts;
29	}
30	
31	// A pack of exactly COMPONENT_BLOCK_SIZE of one component type is offered
32	// at the special block premium; otherwise components are priced individually.
33	function componentsBasePremium(items: Item[]): number {
34	  const componentItems = items.filter((i) => isComponentType(i.type));
35	  const counts = countByType(componentItems);
36	  let total = 0;
37	  for (const type of Object.keys(counts)) {
38	    const count = counts[type];
39	    if (count === COMPONENT_BLOCK_SIZE) {
40	      total += COMPONENT_BLOCK_PREMIUM;
41	    } else {
42	      total += count * getItemSpec(type).basePremium;
43	    }
44	  }
45	  return total;
46	}
47	
48	function mainItemsBasePremium(items: Item[]): number {
49	  return items
50	    .filter((i) => !isComponentType(i.type))
51	    .reduce((sum, item) => sum + basePremiumFor(item), 0);
52	}
53	
54	function policyBasePremium(items: Item[]): number {
55	  return mainItemsBasePremium(items) + componentsBasePremium(items);
56	}
57	
58	function itemSurcharge(item: Item): number {
59	  const base = basePremiumFor(item);
60	  let surcharge = 0;
61	  if (item.cursed) {
62	    surcharge += base * CURSE_SURCHARGE;
63	  }
64	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
65	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE;
66	  }
67	  return surcharge;
68	}
69	
70	function totalItemSurcharges(items: Item[]): number {
71	  return items.reduce((sum, item) => sum + itemSurcharge(item), 0);
72	}
73	
74	function validateItems(items: Item[]): void {
75	  for (const item of items) {
76	    if (!isKnownType(item.type)) {
77	      throw new Error(`Unknown item type: ${item.type}`);
78	    }
79	  }
80	}
81	
82	export interface PremiumContext {
83	  customer: Customer;
84	  quoteIndex: number; // 0-based index among quotes in scenario
85	}
86	
87	// Policy-wide modifiers (loyalty, first insurance, follow-up contract) apply
88	// to the policy base premium — the sum of item base premiums, exclusive of
89	// item-specific surcharges. The processing fee is added last.
90	export function computePremium(items: Item[], ctx: PremiumContext): number {
91	  validateItems(items);
92	
93	  const policyBase = policyBasePremium(items);
94	  let total = policyBase + totalItemSurcharges(items);
95	
96	  if (ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS) {
97	    total -= policyBase * LOYALTY_DISCOUNT;
98	  }
99	  total += policyBase * FIRST_INSURANCE_SURCHARGE;
100	  if (ctx.quoteIndex > 0) {
101	    total -= policyBase * FOLLOWUP_CONTRACT_DISCOUNT;
102	  }
103	  total += PROCESSING_FEE;
104	
105	  return Math.ceil(total);
106	}

