1	import { Scenario, ScenarioResult, StepResult, Policy, Step } from './types.js';
2	import { computePremium } from './premium.js';
3	import { makePolicy } from './policy.js';
4	import { processClaim } from './claim.js';
5	
6	export function runScenario(scenario: Scenario): ScenarioResult {
7	  const results: StepResult[] = [];
8	  const policies = new Map<number, Policy>();
9	  let quoteCount = 0;
10	
11	  scenario.steps.forEach((step: Step, stepIndex: number) => {
12	    if (step.op === 'quote') {
13	      const premium = computePremium(step.items, {
14	        customer: scenario.customer,
15	        quoteIndex: quoteCount,
16	      });
17	      policies.set(stepIndex, makePolicy(step.items));
18	      quoteCount += 1;
19	      results.push({ premium });
20	      return;
21	    }
22	
23	    const policy = policies.get(step.policy);
24	    if (!policy) {
25	      throw new Error(
26	        `Claim step ${stepIndex} references non-existent policy ${step.policy}`
27	      );
28	    }
29	    results.push(processClaim(policy, step.incident));
30	  });
31	
32	  return { results };
33	}
